import "container/heap"

func solve(m int64, n int64, waitCost [][]int64) int64 {
    const INF = 1 << 63 - 1
    dir := [][2]int{{0, 1}, {1, 0}} // right, down
    dist := make([][]int64, m)
    for i := range dist {
        dist[i] = make([]int64, n)
        for j := range dist[i] {
            dist[i][j] = INF
        }
    }
    dist[0][0] = 1 // initial cost to enter (0, 0)

    type Item struct {
        time  int64
        row   int64
        col   int64
        cost  int64
    }

    pq := make(PriorityQueue, 1)
    pq[0] = Item{0, 0, 0, 1}
    heap.Init(&pq)

    for pq.Len() > 0 {
        item := heap.Pop(&pq).(Item)
        time, row, col, cost := item.time, item.row, item.col, item.cost

        if row == m-1 && col == n-1 {
            break
        }

        if time%2 == 1 {
            // Move: right or down
            for _, d := range dir {
                newRow := row + d[0]
                newCol := col + d[1]
                if newRow >= 0 && newRow < m && newCol >= 0 && newCol < n {
                    newTime := time + 1
                    newCost := (newRow + 1) * (newCol + 1)
                    if dist[newRow][newCol] > cost+newCost {
                        dist[newRow][newCol] = cost + newCost
                        heap.Push(&pq, Item{newTime, newRow, newCol, dist[newRow][newCol]})
                    }
                }
            }
        } else {
            // Wait: even time, wait exactly 1 second
            newTime := time + 1
            newCost := cost + waitCost[int(row)][int(col)]
            if dist[int(row)][int(col)] > newCost {
                dist[int(row)][int(col)] = newCost
                heap.Push(&pq, Item{newTime, row, col, dist[int(row)][int(col)]})
            }
        }
    }

    return dist[m-1][n-1]
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
    return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
    pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
    item := x.(*Item)
    *pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
    old := *pq
    n := len(old)
    item := old[n-1]
    *pq = old[0 : n-1]
    return item
}
